    public class CertificateManager
    {
        public static X509Certificate2 LoadCertificateFromStore(string thumbprint, StoreName storeName, StoreLocation storeLocation)
        {
            X509Store store = new X509Store(storeName, storeLocation);
            try
            {
                store.Open(OpenFlags.ReadOnly);
                X509Certificate2Collection certificates = store.Certificates.Find(
                    X509FindType.FindByThumbprint,
                    thumbprint,
                    true);

                if (certificates.Count == 0)
                {
                    throw new InvalidOperationException($"Certificate with thumbprint {thumbprint} not found");
                }

                return certificates[0];
            }
            finally
            {
                store.Close();
            }
        }

        public static X509Certificate2 GenerateSelfSignedCertificate(string subjectName, int validityYears = 5)
        {
            using (RSA rsa = RSA.Create(4096))
            {
                var request = new CertificateRequest(
                    $"CN={subjectName}",
                    rsa,
                    HashAlgorithmName.SHA256,
                    RSASignaturePadding.Pkcs1);

                request.CertificateExtensions.Add(
                    new X509KeyUsageExtension(
                        X509KeyUsageFlags.DataEncipherment | X509KeyUsageFlags.KeyEncipherment | X509KeyUsageFlags.DigitalSignature,
                        false));

                request.CertificateExtensions.Add(
                    new X509EnhancedKeyUsageExtension(
                        new OidCollection {
                            new Oid("1.3.6.1.5.5.7.3.1"),
                            new Oid("1.3.6.1.5.5.7.3.2")
                        },
                        false));

                request.CertificateExtensions.Add(
                    new X509SubjectKeyIdentifierExtension(request.PublicKey, false));

                var certificate = request.CreateSelfSigned(
                    DateTimeOffset.Now.AddDays(-1),
                    DateTimeOffset.Now.AddYears(validityYears));

                return new X509Certificate2(certificate.Export(X509ContentType.Pfx), (string)null, X509KeyStorageFlags.Exportable);
            }
        }
    }

